// ─── SUPABASE CLIENT INITIALIZATION ─────────────────────
// This file initializes the Supabase client for database operations

const SUPABASE_URL = process.env.REACT_APP_SUPABASE_URL;
const SUPABASE_ANON_KEY = process.env.REACT_APP_SUPABASE_ANON_KEY;

// Simple Supabase REST API client (without installing @supabase/supabase-js)
class SupabaseClient {
  constructor(url, anonKey) {
    this.url = url;
    this.anonKey = anonKey;
    this.ready = !!(url && anonKey);
  }

  async request(method, path, body = null, headers = {}) {
    if (!this.ready) {
      throw new Error('Supabase not configured. Check your .env.local file.');
    }

    const fullUrl = `${this.url}/rest/v1${path}`;
    const defaultHeaders = {
      'apikey': this.anonKey,
      'Authorization': `Bearer ${this.anonKey}`,
      'Content-Type': 'application/json',
    };

    const options = {
      method,
      headers: { ...defaultHeaders, ...headers },
    };

    if (body) {
      options.body = JSON.stringify(body);
    }

    const response = await fetch(fullUrl, options);
    
    if (!response.ok) {
      const error = await response.text();
      throw new Error(`Supabase ${method} ${path}: ${response.status} - ${error}`);
    }

    // Return empty for DELETE or no content
    if (method === 'DELETE' || response.status === 204) {
      return null;
    }

    return await response.json();
  }

  async getProducts() {
    return this.request('GET', '/products?order=id.desc');
  }

  async addProduct(product) {
    return this.request('POST', '/products', product);
  }

  async updateProduct(id, product) {
    return this.request('PATCH', `/products?id=eq.${id}`, product);
  }

  async deleteProduct(id) {
    return this.request('DELETE', `/products?id=eq.${id}`);
  }

  async getCategories() {
    return this.request('GET', '/categories?order=id.desc');
  }

  async addCategory(category) {
    return this.request('POST', '/categories', category);
  }

  async updateCategory(id, category) {
    return this.request('PATCH', `/categories?id=eq.${id}`, category);
  }

  async deleteCategory(id) {
    return this.request('DELETE', `/categories?id=eq.${id}`);
  }

  async getAds() {
    return this.request('GET', '/ads?order=id.desc');
  }

  async addAd(ad) {
    return this.request('POST', '/ads', ad);
  }

  async updateAd(id, ad) {
    return this.request('PATCH', `/ads?id=eq.${id}`, ad);
  }

  async deleteAd(id) {
    return this.request('DELETE', `/ads?id=eq.${id}`);
  }
}

// Initialize and export
export const supabase = new SupabaseClient(SUPABASE_URL, SUPABASE_ANON_KEY);
export { SupabaseClient };
